const carriers = $input.item.json.carriers || [];
const rows = carriers.map(function (c) {
  return { vertical_id: 'insurance', carrier_name: c.name, carrier_code: c.code, carrier_type: c.type, province_licensed: c.provinces, ai_compliance_ready: !!c.ai, digital_quote_ready: !!c.digital, contact_email: c.email || null, active: true };
});
return { json: { rows } };

const carrierRows = Array.isArray($input.item.json) ? $input.item.json : [];
const byCode = {};
carrierRows.forEach(function (r) { if (r.carrier_code) byCode[r.carrier_code] = r.id; });
const productsByCode = $('Build Seed Data').first().json.products || {};
const rows = [];
Object.keys(productsByCode).forEach(function (code) {
  const carrierId = byCode[code];
  if (!carrierId) return;
  (productsByCode[code] || []).forEach(function (p) {
    rows.push({
      vertical_id: 'insurance',
      carrier_id: carrierId,
      product_name: p.name,
      product_type: p.type,
      min_coverage_cents: p.min,
      max_coverage_cents: p.max,
      base_premium_cents: p.base,
      commission_first_year: p.fy,
      commission_renewal: p.ren,
      ai_compliance_ready: !!p.ai,
      features: Array.isArray(p.features) ? p.features : [],
      active: true
    });
  });
});
return { json: { rows, carriers_seeded: carrierRows.length, products_to_seed: rows.length } };
